#include <bits/stdc++.h>
using namespace std;
const unsigned long long p=113;
unsigned long long h[1000006],w[1000006];
int m;
string s;
unsigned long long find_hash(int l,int r){
	if(l==1)return h[r];
	return h[r]-(h[l-1]*w[r-l+1]);
}
int main(){
	cin>>s;
	cin>>m;
	w[0]=1;
	for(int i=0;i<s.size();i++){
		h[i+1]=h[i]*p+s[i];
		w[i+1]=w[i]*p;
		//cout<<h[i+1]<<' ';
	}
	//cout<<endl;
	while(m--){
		int l1,r1,l2,r2;
		cin>>l1>>r1>>l2>>r2;
		//cout<<find_hash(l1,r1)<<' '<<find_hash(l2,r2)<<endl;
		if(find_hash(l1,r1)==find_hash(l2,r2))cout<<"Yes\n";
		else cout<<"No\n";
	}
    return 0;
}
